(* ================================================================
   Stripe Payment Reference Model
   Version: 2024-12
   Source: Stripe PaymentIntent + Charge API documentation

   This is the canonical formal model of the Stripe payment
   lifecycle. Agent formalizations of payment code must be
   verified against this model.
   ================================================================ *)

(* ---- PaymentIntent statuses ---- *)

type pi_status =
  | RequiresPaymentMethod
  | RequiresConfirmation
  | RequiresAction        (* 3D Secure / SCA challenge *)
  | Processing            (* async settlement *)
  | RequiresCapture       (* manual capture: authorized, not captured *)
  | Succeeded             (* terminal: payment complete *)
  | Canceled              (* terminal: intent invalidated *)

(* ---- Charge statuses ---- *)

type charge_status = Pending | ChargeSucceeded | ChargeFailed

(* ---- Refund statuses ---- *)

type refund_status =
  | RefundPending | RefundSucceeded | RefundFailed
  | RefundCanceled | RefundRequiresAction

(* ---- Dispute statuses ---- *)

type dispute_status =
  | WarningNeedsResponse | WarningUnderReview | WarningClosed
  | NeedsResponse | Won | Lost

(* ---- Capture method ---- *)

type capture_method = Automatic | Manual

(* ---- Core objects ---- *)

type charge = {
  charge_amount : int;
  amount_captured : int;
  amount_refunded : int;
  charge_status : charge_status;
  captured : bool;
  refunded : bool;
  paid : bool;
}

type payment_intent = {
  pi_amount : int;
  amount_capturable : int;
  amount_received : int;
  pi_status : pi_status;
  capture_method : capture_method;
  latest_charge : charge option;
  three_ds_required : bool;
  three_ds_completed : bool;
}

(* ---- Invariants ---- *)

(* Core amount invariant on charges *)
let inv_charge_amounts (c : charge) : bool =
  0 <= c.amount_refunded &&
  c.amount_refunded <= c.amount_captured &&
  c.amount_captured <= c.charge_amount &&
  c.charge_amount > 0

(* Refunded flag consistency *)
let inv_refunded_flag (c : charge) : bool =
  c.refunded = (c.amount_refunded = c.amount_captured && c.amount_captured > 0)

(* PaymentIntent amount consistency *)
let inv_pi_amounts (pi : payment_intent) : bool =
  pi.pi_amount > 0 &&
  0 <= pi.amount_capturable &&
  0 <= pi.amount_received &&
  pi.amount_capturable + pi.amount_received <= pi.pi_amount

(* Terminal states cannot transition *)
let is_terminal (pi : payment_intent) : bool =
  pi.pi_status = Succeeded || pi.pi_status = Canceled

(* ---- State transitions ---- *)

(* Attach payment method: RequiresPaymentMethod -> RequiresConfirmation *)
let attach_payment_method (pi : payment_intent) : payment_intent =
  if pi.pi_status = RequiresPaymentMethod then
    { pi with pi_status = RequiresConfirmation }
  else pi

(* Confirm payment intent *)
let confirm (pi : payment_intent) : payment_intent =
  if pi.pi_status = RequiresConfirmation then
    if pi.three_ds_required && not pi.three_ds_completed then
      (* 3DS challenge needed *)
      { pi with pi_status = RequiresAction }
    else if pi.capture_method = Manual then
      (* Manual capture: authorize only *)
      { pi with
        pi_status = RequiresCapture;
        amount_capturable = pi.pi_amount;
        latest_charge = Some {
          charge_amount = pi.pi_amount;
          amount_captured = 0;
          amount_refunded = 0;
          charge_status = Pending;
          captured = false;
          refunded = false;
          paid = true;
        }
      }
    else
      (* Auto capture: charge immediately *)
      { pi with
        pi_status = Succeeded;
        amount_received = pi.pi_amount;
        amount_capturable = 0;
        latest_charge = Some {
          charge_amount = pi.pi_amount;
          amount_captured = pi.pi_amount;
          amount_refunded = 0;
          charge_status = ChargeSucceeded;
          captured = true;
          refunded = false;
          paid = true;
        }
      }
  else pi

(* Complete 3D Secure challenge *)
let complete_three_ds (pi : payment_intent) : payment_intent =
  if pi.pi_status = RequiresAction && pi.three_ds_required then
    let pi2 = { pi with three_ds_completed = true } in
    if pi2.capture_method = Manual then
      { pi2 with
        pi_status = RequiresCapture;
        amount_capturable = pi2.pi_amount;
        latest_charge = Some {
          charge_amount = pi2.pi_amount;
          amount_captured = 0;
          amount_refunded = 0;
          charge_status = Pending;
          captured = false;
          refunded = false;
          paid = true;
        }
      }
    else
      { pi2 with
        pi_status = Succeeded;
        amount_received = pi2.pi_amount;
        latest_charge = Some {
          charge_amount = pi2.pi_amount;
          amount_captured = pi2.pi_amount;
          amount_refunded = 0;
          charge_status = ChargeSucceeded;
          captured = true;
          refunded = false;
          paid = true;
        }
      }
  else pi

(* Fail 3D Secure -> back to requires_payment_method *)
let fail_three_ds (pi : payment_intent) : payment_intent =
  if pi.pi_status = RequiresAction then
    { pi with pi_status = RequiresPaymentMethod; three_ds_completed = false }
  else pi

(* Capture payment (manual capture mode) *)
let capture (amt : int) (pi : payment_intent) : payment_intent =
  if pi.pi_status = RequiresCapture && amt > 0 && amt <= pi.amount_capturable then
    match pi.latest_charge with
    | None -> pi
    | Some c ->
      let new_captured = c.amount_captured + amt in
      { pi with
        pi_status = Succeeded;
        amount_received = new_captured;
        amount_capturable = 0;
        latest_charge = Some {
          c with
          amount_captured = new_captured;
          charge_status = ChargeSucceeded;
          captured = true;
        }
      }
  else pi

(* Cancel payment intent *)
let cancel_pi (pi : payment_intent) : payment_intent =
  if pi.pi_status <> Succeeded && pi.pi_status <> Canceled then
    { pi with
      pi_status = Canceled;
      amount_capturable = 0;
    }
  else pi

(* Refund (on a succeeded payment) *)
let refund (amt : int) (pi : payment_intent) : payment_intent =
  if pi.pi_status = Succeeded && amt > 0 then
    match pi.latest_charge with
    | None -> pi
    | Some c ->
      let remaining = c.amount_captured - c.amount_refunded in
      if amt <= remaining then
        let new_refunded = c.amount_refunded + amt in
        { pi with
          latest_charge = Some {
            c with
            amount_refunded = new_refunded;
            refunded = (new_refunded = c.amount_captured);
          }
        }
      else pi
  else pi

(* ---- Verification goals ---- *)

(* VG1: confirm preserves amount invariant *)
verify (fun (pi : payment_intent) ->
  inv_pi_amounts pi ==> inv_pi_amounts (confirm pi))

(* VG2: capture preserves amount invariant *)
verify (fun (amt : int) (pi : payment_intent) ->
  inv_pi_amounts pi ==> inv_pi_amounts (capture amt pi))

(* VG3: refund preserves charge amount invariant *)
verify (fun (amt : int) (pi : payment_intent) ->
  inv_pi_amounts pi ==>
  match pi.latest_charge with
  | None -> true
  | Some c -> inv_charge_amounts c ==>
    match (refund amt pi).latest_charge with
    | None -> true
    | Some c2 -> inv_charge_amounts c2)

(* VG4: cancel from non-terminal is always valid *)
verify (fun (pi : payment_intent) ->
  not (is_terminal pi) ==>
  (cancel_pi pi).pi_status = Canceled)

(* VG5: succeeded is terminal *)
verify (fun (pi : payment_intent) ->
  pi.pi_status = Succeeded ==>
  confirm pi = pi &&
  capture 1 pi = pi &&
  cancel_pi pi = pi)

(* VG6: 3DS blocks authorization *)
verify (fun (pi : payment_intent) ->
  pi.pi_status = RequiresConfirmation &&
  pi.three_ds_required &&
  not pi.three_ds_completed ==>
  (confirm pi).pi_status = RequiresAction)

(* VG7: refunded flag consistency *)
verify (fun (amt : int) (pi : payment_intent) ->
  pi.pi_status = Succeeded ==>
  match (refund amt pi).latest_charge with
  | None -> true
  | Some c -> inv_refunded_flag c)

(* ================================================================
   Plaid Link & Transactions Reference Model
   Version: 2024-09
   Source: Plaid API documentation

   Formal model of the Plaid Link token lifecycle and
   transaction sync protocol. Covers: link token creation,
   item connection, access token exchange, transaction sync
   with cursor-based pagination, and webhook notifications.
   ================================================================ *)

(* ---- Link token lifecycle ---- *)

type link_token_status =
  | LinkCreated          (* token created, not yet used *)
  | LinkInProgress       (* user is in Link flow *)
  | LinkSucceeded        (* user connected institution *)
  | LinkExited           (* user exited without connecting *)
  | LinkExpired          (* token expired (30 min TTL) *)

(* ---- Item (connected account) states ---- *)

type item_status =
  | ItemActive           (* healthy connection *)
  | ItemNeedsUpdate      (* credentials need refresh *)
  | ItemRevoked          (* user revoked access *)
  | ItemSuspended        (* Plaid suspended due to errors *)

(* ---- Transaction sync states ---- *)

type sync_status =
  | SyncInitial          (* first sync, no cursor *)
  | SyncInProgress       (* paginating through results *)
  | SyncComplete         (* all pages consumed, has_more = false *)

type cursor = string option

(* ---- Core objects ---- *)

type link_token = {
  lt_client_id : string;
  lt_user_id : string;
  lt_status : link_token_status;
  lt_expiration_ttl : int;  (* seconds, max 1800 *)
}

type access_token = {
  at_item_id : string;
  at_status : item_status;
  at_institution_id : string;
}

type transaction = {
  tx_id : string;
  tx_amount : int;        (* in cents, positive = debit *)
  tx_pending : bool;
  tx_category : string;
}

type sync_response = {
  added : transaction list;
  modified : transaction list;
  removed : string list;   (* removed transaction IDs *)
  next_cursor : string;
  has_more : bool;
}

type sync_state = {
  ss_cursor : cursor;
  ss_status : sync_status;
  ss_total_added : int;
  ss_total_modified : int;
  ss_total_removed : int;
}

(* ---- Invariants ---- *)

(* Link token TTL must be positive and <= 30 minutes *)
let inv_link_ttl (lt : link_token) : bool =
  0 < lt.lt_expiration_ttl &&
  lt.lt_expiration_ttl <= 1800

(* Sync state counts must be non-negative *)
let inv_sync_counts (ss : sync_state) : bool =
  ss.ss_total_added >= 0 &&
  ss.ss_total_modified >= 0 &&
  ss.ss_total_removed >= 0

(* Transaction amounts are non-zero *)
let inv_transaction (tx : transaction) : bool =
  tx.tx_amount <> 0

(* ---- State transitions ---- *)

(* Create a link token *)
let create_link_token (client_id : string) (user_id : string) : link_token =
  { lt_client_id = client_id;
    lt_user_id = user_id;
    lt_status = LinkCreated;
    lt_expiration_ttl = 1800; }

(* User starts Link flow *)
let start_link (lt : link_token) : link_token =
  if lt.lt_status = LinkCreated then
    { lt with lt_status = LinkInProgress }
  else lt

(* User successfully connects institution *)
let complete_link (lt : link_token) : link_token =
  if lt.lt_status = LinkInProgress then
    { lt with lt_status = LinkSucceeded }
  else lt

(* User exits without connecting *)
let exit_link (lt : link_token) : link_token =
  if lt.lt_status = LinkInProgress then
    { lt with lt_status = LinkExited }
  else lt

(* Token expires *)
let expire_link (lt : link_token) : link_token =
  if lt.lt_status = LinkCreated || lt.lt_status = LinkInProgress then
    { lt with lt_status = LinkExpired }
  else lt

(* Exchange public token for access token *)
let exchange_token (lt : link_token) (institution_id : string) : access_token option =
  if lt.lt_status = LinkSucceeded then
    Some { at_item_id = "item_" ^ lt.lt_user_id;
           at_status = ItemActive;
           at_institution_id = institution_id; }
  else None

(* Process a sync response page *)
let process_sync_page (resp : sync_response) (ss : sync_state) : sync_state =
  { ss_cursor = Some resp.next_cursor;
    ss_status = if resp.has_more then SyncInProgress else SyncComplete;
    ss_total_added = ss.ss_total_added + List.length resp.added;
    ss_total_modified = ss.ss_total_modified + List.length resp.modified;
    ss_total_removed = ss.ss_total_removed + List.length resp.removed; }

(* Initial sync state *)
let initial_sync_state : sync_state =
  { ss_cursor = None;
    ss_status = SyncInitial;
    ss_total_added = 0;
    ss_total_modified = 0;
    ss_total_removed = 0; }

(* ---- Verification goals ---- *)

(* VG1: link token lifecycle is monotonic (no going back) *)
verify (fun (lt : link_token) ->
  lt.lt_status = LinkSucceeded ==>
  complete_link lt = lt &&
  start_link lt = lt)

(* VG2: exchange only works after successful link *)
verify (fun (lt : link_token) (inst : string) ->
  lt.lt_status <> LinkSucceeded ==>
  exchange_token lt inst = None)

(* VG3: sync counts are monotonically non-decreasing *)
verify (fun (resp : sync_response) (ss : sync_state) ->
  inv_sync_counts ss ==>
  inv_sync_counts (process_sync_page resp ss))

(* VG4: completed sync has a cursor *)
verify (fun (resp : sync_response) (ss : sync_state) ->
  not resp.has_more ==>
  (process_sync_page resp ss).ss_status = SyncComplete &&
  (process_sync_page resp ss).ss_cursor <> None)
